链栈定义链栈是用链式存储实现的 栈。通常把链表头部作为栈顶，因为头插和头删都只需要 O(1)。 typedef struct StackNode &#123; ElemType data; struct StackNode *next;&#125; StackNode, *LinkStack;
不带头结点时，空栈可表示为： LinkStack top = NULL;
进栈进栈等价于单链表头插： bool Push(LinkStack *top, ElemType value) &#123; StackNode *newNode = (StackNode *)malloc(sizeof(StackNode)); if (newNode == NULL) return false; newNode-&gt;data = value; newNode-&gt;next = *top; *top = newNode; return true;&#125;
先让 newNode-&gt;next 指向原栈顶，再更新 top，这样原栈不会丢失。 出栈出栈等价于单链表头删： bool Pop(LinkStack *top, ElemType *value) &#123; if (*top == NULL) return false; StackNode *target = *top; *value = target-&gt;data; *top = target-&gt;next; free(target); return true;&#125;
需要先保存原栈顶结点 target，否则更新 top 后不方便释放原结点。 特点 不需要预先确定最大容量。 结点需要额外指针域，空间开销比顺序栈大。 只要内存可申请，通常不考虑“栈满”；但申请失败仍要处理。
链栈和 单链表头插头删 的代码结构非常接近，区别在于链栈只暴露栈顶操作。

链队列定义链队列是用链式存储实现的 队列。通常设置队头指针 front 和队尾指针 rear。 带头结点的链队列结构： typedef struct LinkNode &#123; ElemType data; struct LinkNode *next;&#125; LinkNode;typedef struct &#123; LinkNode *front; LinkNode *rear;&#125; LinkQueue;
带头结点初始化bool InitQueue(LinkQueue *queue) &#123; LinkNode *head = (LinkNode *)malloc(sizeof(LinkNode)); if (head == NULL) return false; head-&gt;next = NULL; queue-&gt;front = head; queue-&gt;rear = head; return true;&#125;
带头结点时，空队列满足： queue.front == queue.rear
入队入队发生在队尾： bool EnQueue(LinkQueue *queue, ElemType value) &#123; LinkNode *newNode = (LinkNode *)malloc(sizeof(LinkNode)); if (newNode == NULL) return false; newNode-&gt;data = value; newNode-&gt;next = NULL; queue-&gt;rear-&gt;next = newNode; queue-&gt;rear = newNode; return true;&#125;
先让原队尾接上新结点，再更新 rear。 出队出队删除队头结点的后继： bool DeQueue(LinkQueue *queue, ElemType *value) &#123; if (queue-&gt;front == queue-&gt;rear) return false; LinkNode *target = queue-&gt;front-&gt;next; *value = target-&gt;data; queue-&gt;front-&gt;next = target-&gt;next; if (queue-&gt;rear == target) &#123; queue-&gt;rear = queue-&gt;front; &#125; free(target); return true;&#125;
若删除的是最后一个数据结点，必须让 rear 回到头结点，否则 rear 会悬空。 不带头结点的特殊情况不带头结点时，空队列通常满足： queue.front == NULL &amp;&amp; queue.rear == NULL
第一次入队和删除最后一个结点都需要特殊处理。考试中若未说明，带头结点链队列更容易写出统一代码。

1. 什么是中介者模式？中介者模式（Mediator Pattern）通过引入一个“中介者”对象来封装对象之间的交互，使多个对象不需要显式引用彼此，改为只与中介者通信。它将协作编排从同事对象中抽离出来，降低耦合并集中管理交互规则。 2. 为什么需要中介者模式？一个复杂的软件系统，若每个对象都与其他许多对象直接关联，则它们之间产生了紧密的耦合。这种设计的后果是，对任何一个对象的修改都可能引发连锁反应，迫使其他相关对象也得跟着改动，这便是“牵一发而动全身”的困境。系统的维护成本因此急剧攀升。 更糟糕的是，完整的业务流程被切割得支离破碎，散落在各个对象的实现中。想要理解一个完整的协作过程，开发者不得不深入多个类，追踪复杂的调用链，这使得系统的整体行为变得难以把握，也让新功能的添加或问题排查变得困难。同时，由于每个对象都和它的“同事们”绑得太死，想把它单独拿出来在别处复用也几乎不可能。 中介者模式正是为了解开这个“死结”而提出的。它引入了一个中心协调者——“中介者”，所有对象不再互相直接通信，而是统一与中介者对话。中介者负责接收消息，并根据既定规则将其分发给正确的对象。这样，原本混乱的网状结构被重构为清晰的“星型结构”，所有复杂的交互逻辑都集中到了中介者内部。通过这种方式，对象之间得以解耦，系统也因此变得更加清晰、易于维护和扩展。 3. 中介者模式的实现（go）下面用一个简化的聊天室演示中介者如何协调用户之间的消息传递。 package mainimport ( &quot;fmt&quot;)type Mediator interface &#123; Register(c Colleague) Send(from string, to string, msg string) Broadcast(from string, msg string)&#125;type Colleague interface &#123; Name() string Receive(from string, msg string) Send(to string, msg string) Broadcast(msg string)&#125;type ChatRoom struct &#123; members map[string]Colleague&#125;func NewChatRoom() *ChatRoom &#123; return &amp;ChatRoom&#123;members: make(map[string]Colleague)&#125;&#125;func (r *ChatRoom) Register(c Colleague) &#123; r.members[c.Name()] = c&#125;func (r *ChatRoom) Send(from string, to string, msg string) &#123; if m, ok := r.members[to]; ok &#123; m.Receive(from, msg) &#125;&#125;func (r *ChatRoom) Broadcast(from string, msg string) &#123; for name, m := range r.members &#123; if name == from &#123; continue &#125; m.Receive(from, msg) &#125;&#125;type User struct &#123; name string room *ChatRoom&#125;func NewUser(name string, room *ChatRoom) *User &#123; return &amp;User&#123;name: name, room: room&#125;&#125;func (u *User) Name() string &#123; return u.name &#125;func (u *User) Receive(from string, msg string) &#123; fmt.Printf(&quot;[%s] &lt;- %s: %s\n&quot;, u.name, from, msg)&#125;func (u *User) Send(to string, msg string) &#123; u.room.Send(u.name, to, msg)&#125;func (u *User) Broadcast(msg string) &#123; u.room.Broadcast(u.name, msg)&#125;func main() &#123; room := NewChatRoom() alice := NewUser(&quot;alice&quot;, room) bob := NewUser(&quot;bob&quot;, room) eve := NewUser(&quot;eve&quot;, room) room.Register(alice) room.Register(bob) room.Register(eve) alice.Send(&quot;bob&quot;, &quot;Hi Bob&quot;) bob.Send(&quot;alice&quot;, &quot;Hi Alice&quot;) eve.Broadcast(&quot;Hello everyone&quot;)&#125;
要点：用户之间不直接互相引用，交互规则集中在 ChatRoom。当需要增加记录审计、敏感词过滤、分组路由时，仅需扩展中介者。 类图：
classDiagram class mediator { &lt;&lt;interface&gt;&gt; +Register(c colleague) +Send(from,to,msg) +Broadcast(from,msg) } class concreteMediator { +Register(c colleague) +Send(from,to,msg) +Broadcast(from,msg) } class colleague { &lt;&lt;interface&gt;&gt; +Name() string +Receive(from,msg) +Send(to,msg) +Broadcast(msg) } class concreteColleague { +Name() string +Receive(from,msg) +Send(to,msg) +Broadcast(msg) }
