1. 什么是观察者模式？观察者模式（Observer Pattern）用于在对象状态变化时，通知依赖它的多个观察者，实现一种一对多的订阅关系。被观察者只负责发布事件，不关心有多少观察者、它们如何处理，达到发布方与订阅方的解耦。
2. 为什么需要观察者模式？当一个对象的变化需要联动多个组件时，若直接在对象内部逐个调用这些组件，将产生紧耦合和复杂的依赖。当组件增删或行为变化时，被观察者也不得不调整。通过观察者模式，我们将事件的发布与处理分离：被观察者只负责发出信号，观察者各自处理，从而降低耦合、提高扩展性。
3. 观察者模式的实现（go）type Observer interface &#123;    Update(event string, data any)&#125;type Subject interface &#123;    Register(o Observer)    Unregister(o Observer)    Notify(event string, data any)&#125;type Topic struct &#123;    observers []Observer&#125;func (t *Topic) Register(o Observer) &#123;    t.observers = append(t.observers, o)&#125;func (t *Topic) Unregister(o Observer) &#123;    i := -1    for idx, ob := range t.observers &#123;        if ob == o &#123;            i = idx            break        &#125;    &#125;    if i &gt;= 0 &#123;        t.observers = append(t.observers[:i], t.observers[i+1:]...)    &#125;&#125;func (t *Topic) Notify(event string, data any) &#123;    for _, o := range t.observers &#123;        o.Update(event, data)    &#125;&#125;type PrintObserver struct &#123;    name string&#125;func (p *PrintObserver) Update(event string, data any) &#123;    fmt.Printf(&quot;[%s] %s: %v\n&quot;, p.name, event, data)&#125;

客户端代码如下：
func main() &#123;    t := &amp;Topic&#123;&#125;    a := &amp;PrintObserver&#123;name: &quot;A&quot;&#125;    b := &amp;PrintObserver&#123;name: &quot;B&quot;&#125;    t.Register(a)    t.Register(b)    t.Notify(&quot;price_changed&quot;, 42)    t.Unregister(a)    t.Notify(&quot;price_changed&quot;, 43)&#125;

输出：
[A] price_changed: 42[B] price_changed: 42[B] price_changed: 43

